import{r as s,j as a}from"./react-CSMq4t3t.js";import{L as e}from"./react-router-CWvL_sQr.js";import"./cookie-CXUWDbkB.js";import"./react-dom-CyqBZZYC.js";import"./scheduler-6ULW7vKx.js";const n=()=>{const[n,r]=s.useState(null);return a.jsx("div",{className:"faq-page",children:a.jsxs("div",{className:"faq-container",children:[a.jsx(e,{to:"/",className:"faq-back",children:"الرئيسية →"}),a.jsxs("div",{className:"faq-header",children:[a.jsx("h1",{children:"الأسئلة الشائعة"}),a.jsx("p",{children:"إجابات على الأسئلة الأكثر شيوعاً حول منصة SQB"})]}),a.jsx("div",{className:"faq-list",children:[{question:"ما هي منصة SQB؟",answer:"SQB (SMLE Question Bank) هي منصة تعليمية متخصصة في التحضير لاختبار الهيئة السعودية للتخصصات الصحية (SMLE) واختبار البرومترك. توفر المنصة أكثر من 11,000 سؤال طبي مع تحليلات مفصلة وتتبع أداء شامل."},{question:"كم عدد الأسئلة المتاحة؟",answer:"تحتوي المنصة على أكثر من 11,000 سؤال طبي تغطي أكثر من 40 تخصص طبي مختلف، تشمل Internal Medicine، Surgery، Pediatric، OB/GYN، والمزيد."},{question:"هل يمكنني تجربة المنصة مجاناً؟",answer:"نعم. يمكنك إنشاء حساب مجاني والبدء مباشرة في التدريب. بعض المزايا المتقدمة قد تختلف حسب نوع الحساب."},{question:"ما هي أنواع الاختبارات المتاحة؟",answer:"نوفر اختبارات بأحجام مختلفة تناسب احتياجاتك:\n• اختبار سريع: 10 أسئلة (للمراجعة السريعة)\n• اختبار متوسط: 20 سؤال\n• اختبار طويل: 50 سؤال\n• اختبار شامل: 100 سؤال (يحاكي الاختبار الفعلي)"},{question:"كيف يعمل نظام التحليلات؟",answer:"يوفر نظام التحليلات معلومات مفصلة عن أداءك تشمل:\n• نسبة الإجابات الصحيحة لكل تخصص\n• تتبع التقدم عبر الزمن\n• تحديد المواضيع الضعيفة التي تحتاج مراجعة\n• تاريخ الاختبارات السابقة والنتائج\n• الأسئلة الخاطئة لمراجعتها"},{question:"هل الأسئلة محدّثة؟",answer:"نعم، يتم تحديث بنك الأسئلة بشكل دوري لضمان توافقه مع أحدث المعايير والمحتوى الطبي. فريقنا يعمل باستمرار على إضافة أسئلة جديدة وتحسين الأسئلة الحالية."},{question:"كيف أشترك في المنصة؟",answer:"يمكنك البدء فوراً بخطوات بسيطة:\n1. أنشئ حسابك المجاني\n2. ابدأ أول اختبار سريع\n3. راجع النتائج ونقاط الضعف\n4. استمر يومياً لتحسين مستواك قبل الاختبار"},{question:"هل المنصة تابعة للهيئة السعودية للتخصصات الصحية؟",answer:"لا، SQB هي منصة تعليمية مستقلة وغير تابعة للهيئة السعودية للتخصصات الصحية (SCFHS) أو شركة Prometric أو أي جهة رسمية. الأسئلة المقدمة هي للتدريب والممارسة فقط."},{question:"كيف أتواصل مع الدعم؟",answer:"يمكنك التواصل معنا عبر:\n• واتساب: 0582619119\n• البريد الإلكتروني: alshraky3@gmail.com\n• صفحة الاتصال على الموقع"},{question:"هل يمكنني استخدام المنصة على الجوال؟",answer:"نعم! المنصة مصممة لتعمل بشكل ممتاز على جميع الأجهزة بما في ذلك الهواتف الذكية والأجهزة اللوحية وأجهزة الكمبيوتر. لا تحتاج لتحميل أي تطبيق - استخدم المنصة مباشرة من المتصفح."}].map((s,e)=>a.jsxs("div",{className:"faq-item "+(n===e?"faq-item-open":""),children:[a.jsxs("button",{className:"faq-question",onClick:()=>(s=>{r(n===s?null:s)})(e),"aria-expanded":n===e,children:[a.jsx("span",{children:s.question}),a.jsx("span",{className:"faq-icon",children:n===e?"−":"+"})]}),n===e&&a.jsx("div",{className:"faq-answer",children:s.answer.split("\n").map((s,e)=>a.jsx("p",{children:s},e))})]},e))}),a.jsxs("div",{className:"faq-contact-cta",children:[a.jsx("h2",{children:"لم تجد إجابة لسؤالك؟"}),a.jsx("p",{children:"تواصل معنا وسنكون سعداء بمساعدتك"}),a.jsxs("div",{className:"faq-cta-buttons",children:[a.jsx(e,{to:"/contact",className:"faq-cta-btn",children:"اتصل بنا"}),a.jsx("a",{href:"https://wa.link/gqafib",className:"faq-cta-btn faq-cta-whatsapp",target:"_blank",rel:"noopener noreferrer",children:"واتساب"})]})]})]})})};export{n as default};
